-- Program: Summer Body Countdown
-- Category: Life Events & Milestones -> life_events
-- Priority: High
-- Durations: [4, 8, 12], Sessions: [4, 5, 6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Summer Body Countdown',
    'Countdown to summer with high-intensity circuits for lean muscle',
    'life_events',
    'all_levels',
    12,
    6,
    'full_body',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Summer Body Countdown - 4w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Summer Body Countdown - 4w 4x/wk',
    'life_events',
    4,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Summer Body Countdown'
ON CONFLICT DO NOTHING;

